    12→namespace Monolog\Formatter;
    13→
    14→use Monolog\JsonSerializableDateTimeImmutable;
    15→use Monolog\Utils;
    16→use Throwable;
    17→use Monolog\LogRecord;
    18→
    19→/**
    20→ * Normalizes incoming records to remove objects/resources so it's easier to dump to various targets
    21→ *
    22→ * @author Jordi Boggiano <j.boggiano@seld.be>
    23→ */
    24→class NormalizerFormatter implements FormatterInterface
    25→{
    26→    public const SIMPLE_DATE = "Y-m-d\TH:i:sP";
    27→
    28→    protected string $dateFormat;
    29→    protected int $maxNormalizeDepth = 9;
    30→    protected int $maxNormalizeItemCount = 1000;
    31→
    32→    private int $jsonEncodeOptions = Utils::DEFAULT_JSON_FLAGS;
    33→
    34→    protected string $basePath = '';
    35→
    36→    /**
    37→     * @param string|null $dateFormat The format of the timestamp: one supported by DateTime::format
    38→     */
    39→    public function __construct(?string $dateFormat = null)
    40→    {
    41→        $this->dateFormat = null === $dateFormat ? static::SIMPLE_DATE : $dateFormat;
    42→    }
    43→
    44→    /**
    45→     * @inheritDoc
    46→     */
    47→    public function format(LogRecord $record)
    48→    {
    49→        return $this->normalizeRecord($record);
    50→    }
    51→
    52→    /**
    53→     * Normalize an arbitrary value to a scalar|array|null
    54→     *
    55→     * @return null|scalar|array<mixed[]|scalar|null>
    56→     */
    57→    public function normalizeValue(mixed $data): mixed
    58→    {
    59→        return $this->normalize($data);
    60→    }
    61→
    62→    /**
    63→     * @inheritDoc
    64→     */
    65→    public function formatBatch(array $records)
    66→    {
    67→        foreach ($records as $key => $record) {
    68→            $records[$key] = $this->format($record);
    69→        }
    70→
    71→        return $records;
    72→    }
    73→
    74→    public function getDateFormat(): string
    75→    {
    76→        return $this->dateFormat;
    77→    }
    78→
    79→    /**
    80→     * @return $this
    81→     */
    82→    public function setDateFormat(string $dateFormat): self
    83→    {
    84→        $this->dateFormat = $dateFormat;
    85→
    86→        return $this;
    87→    }
    88→
    89→    /**
    90→     * The maximum number of normalization levels to go through
    91→     */
    92→    public function getMaxNormalizeDepth(): int
    93→    {
    94→        return $this->maxNormalizeDepth;
    95→    }
    96→
    97→    /**
    98→     * @return $this
    99→     */
   100→    public function setMaxNormalizeDepth(int $maxNormalizeDepth): self
   101→    {
   102→        $this->maxNormalizeDepth = $maxNormalizeDepth;
   103→
   104→        return $this;
   105→    }
   106→
   107→    /**
   108→     * The maximum number of items to normalize per level
   109→     */
   110→    public function getMaxNormalizeItemCount(): int
   111→    {
   112→        return $this->maxNormalizeItemCount;
   113→    }
   114→
   115→    /**
   116→     * @return $this
   117→     */
   118→    public function setMaxNormalizeItemCount(int $maxNormalizeItemCount): self
   119→    {
   120→        $this->maxNormalizeItemCount = $maxNormalizeItemCount;
   121→
   122→        return $this;
   123→    }
   124→
   125→    /**
   126→     * Enables `json_encode` pretty print.
   127→     *
   128→     * @return $this
   129→     */
   130→    public function setJsonPrettyPrint(bool $enable): self
   131→    {
   132→        if ($enable) {
   133→            $this->jsonEncodeOptions |= JSON_PRETTY_PRINT;
   134→        } else {
   135→            $this->jsonEncodeOptions &= ~JSON_PRETTY_PRINT;
   136→        }
   137→
   138→        return $this;
   139→    }
   140→
   141→    /**
   142→     * Setting a base path will hide the base path from exception and stack trace file names to shorten them
   143→     * @return $this
   144→     */
   145→    public function setBasePath(string $path = ''): self
   146→    {
   147→        if ($path !== '') {
   148→            $path = rtrim($path, DIRECTORY_SEPARATOR) . DIRECTORY_SEPARATOR;
   149→        }
   150→
   151→        $this->basePath = $path;
   152→
   153→        return $this;
   154→    }
   155→
   156→    /**
   157→     * Provided as extension point
   158→     *
   159→     * Because normalize is called with sub-values of context data etc, normalizeRecord can be
   160→     * extended when data needs to be appended on the record array but not to other normalized data.
   161→     *
   162→     * @return array<mixed[]|scalar|null>
   163→     */
   164→    protected function normalizeRecord(LogRecord $record): array
   165→    {
   166→        /** @var array<mixed[]|scalar|null> $normalized */
   167→        $normalized = $this->normalize($record->toArray());
   168→
   169→        return $normalized;
   170→    }
   171→
   172→    /**
   173→     * @return null|scalar|array<mixed[]|scalar|null>
   174→     */
   175→    protected function normalize(mixed $data, int $depth = 0): mixed
   176→    {
   177→        if ($depth > $this->maxNormalizeDepth) {
   178→            return 'Over ' . $this->maxNormalizeDepth . ' levels deep, aborting normalization';
   179→        }
   180→
   181→        if (null === $data || \is_scalar($data)) {
   182→            if (\is_float($data)) {
   183→                if (is_infinite($data)) {
   184→                    return ($data > 0 ? '' : '-') . 'INF';
   185→                }
   186→                if (is_nan($data)) {
   187→                    return 'NaN';
   188→                }
   189→            }
   190→
   191→            return $data;
   192→        }
   193→
   194→        if (\is_array($data)) {
   195→            $normalized = [];
   196→
   197→            $count = 1;
   198→            foreach ($data as $key => $value) {
   199→                if ($count++ > $this->maxNormalizeItemCount) {
   200→                    $normalized['...'] = 'Over ' . $this->maxNormalizeItemCount . ' items ('.\count($data).' total), aborting normalization';
   201→                    break;
   202→                }
   203→
   204→                $normalized[$key] = $this->normalize($value, $depth + 1);
   205→            }
   206→
   207→            return $normalized;
   208→        }
   209→
   210→        if ($data instanceof \DateTimeInterface) {
   211→            return $this->formatDate($data);
   212→        }
   213→
   214→        if (\is_object($data)) {
   215→            if ($data instanceof Throwable) {
   216→                return $this->normalizeException($data, $depth);
   217→            }
   218→
   219→            if ($data instanceof \JsonSerializable) {
   220→                /** @var null|scalar|array<mixed[]|scalar|null> $value */
   221→                $value = $data->jsonSerialize();
   222→            } elseif (\get_class($data) === '__PHP_Incomplete_Class') {
   223→                $accessor = new \ArrayObject($data);
   224→                $value = (string) $accessor['__PHP_Incomplete_Class_Name'];
   225→            } elseif (method_exists($data, '__toString')) {
   226→                try {
   227→                    /** @var string $value */
   228→                    $value = $data->__toString();
   229→                } catch (\Throwable) {
   230→                    // if the toString method is failing, use the default behavior
   231→                    /** @var null|scalar|array<mixed[]|scalar|null> $value */
   232→                    $value = json_decode($this->toJson($data, true), true);
   233→                }
   234→            } else {
   235→                // the rest is normalized by json encoding and decoding it
   236→                /** @var null|scalar|array<mixed[]|scalar|null> $value */
   237→                $value = json_decode($this->toJson($data, true), true);
   238→            }
   239→
   240→            return [Utils::getClass($data) => $value];
   241→        }
   242→
   243→        if (\is_resource($data)) {
   244→            return sprintf('[resource(%s)]', get_resource_type($data));
   245→        }
   246→
   247→        return '[unknown('.\gettype($data).')]';
   248→    }
   249→
   250→    /**
   251→     * @return array<array-key, string|int|array<string|int|array<string>>>
   252→     */
   253→    protected function normalizeException(Throwable $e, int $depth = 0)
   254→    {
   255→        if ($depth > $this->maxNormalizeDepth) {
   256→            return ['Over ' . $this->maxNormalizeDepth . ' levels deep, aborting normalization'];
   257→        }
   258→
   259→        if ($e instanceof \JsonSerializable) {
   260→            return (array) $e->jsonSerialize();
   261→        }
   262→
   263→        $file = $e->getFile();
   264→        if ($this->basePath !== '') {
   265→            $file = preg_replace('{^'.preg_quote($this->basePath).'}', '', $file);
   266→        }
   267→
   268→        $data = [
   269→            'class' => Utils::getClass($e),
   270→            'message' => $e->getMessage(),
   271→            'code' => (int) $e->getCode(),
   272→            'file' => $file.':'.$e->getLine(),
   273→        ];
   274→
   275→        if ($e instanceof \SoapFault) {
   276→            if (isset($e->faultcode)) {
   277→                $data['faultcode'] = $e->faultcode;
   278→            }
   279→
   280→            if (isset($e->faultactor)) {
   281→                $data['faultactor'] = $e->faultactor;
   282→            }
   283→
   284→            if (isset($e->detail)) {
   285→                if (\is_string($e->detail)) {
   286→                    $data['detail'] = $e->detail;
   287→                } elseif (\is_object($e->detail) || \is_array($e->detail)) {
   288→                    $data['detail'] = $this->toJson($e->detail, true);
   289→                }
   290→            }
   291→        }
   292→
   293→        $trace = $e->getTrace();
   294→        foreach ($trace as $frame) {
   295→            if (isset($frame['file'], $frame['line'])) {
   296→                $file = $frame['file'];
   297→                if ($this->basePath !== '') {
   298→                    $file = preg_replace('{^'.preg_quote($this->basePath).'}', '', $file);
   299→                }
   300→                $data['trace'][] = $file.':'.$frame['line'];
   301→            }
   302→        }
   303→
   304→        if (($previous = $e->getPrevious()) instanceof \Throwable) {
   305→            $data['previous'] = $this->normalizeException($previous, $depth + 1);
   306→        }
   307→
   308→        return $data;
   309→    }
   310→
   311→    /**
   312→     * Return the JSON representation of a value
   313→     *
   314→     * @param  mixed             $data
   315→     * @throws \RuntimeException if encoding fails and errors are not ignored
   316→     * @return string            if encoding fails and ignoreErrors is true 'null' is returned
   317→     */
   318→    protected function toJson($data, bool $ignoreErrors = false): string
   319→    {
   320→        return Utils::jsonEncode($data, $this->jsonEncodeOptions, $ignoreErrors);
   321→    }
   322→
   323→    protected function formatDate(\DateTimeInterface $date): string
   324→    {
   325→        // in case the date format isn't custom then we defer to the custom JsonSerializableDateTimeImmutable
   326→        // formatting logic, which will pick the right format based on whether useMicroseconds is on
   327→        if ($this->dateFormat === self::SIMPLE_DATE && $date instanceof JsonSerializableDateTimeImmutable) {
   328→            return (string) $date;
   329→        }
   330→
   331→        return $date->format($this->dateFormat);
   332→    }
   333→
   334→    /**
   335→     * @return $this
   336→     */
   337→    public function addJsonEncodeOption(int $option): self
   338→    {
   339→        $this->jsonEncodeOptions |= $option;
   340→
   341→        return $this;
   342→    }
   343→
   344→    /**
   345→     * @return $this
   346→     */
   347→    public function removeJsonEncodeOption(int $option): self
   348→    {
   349→        $this->jsonEncodeOptions &= ~$option;
   350→
   351→        return $this;
   352→    }
   353→}
   354→

