    12→namespace Monolog\Formatter;
    13→
    14→use Monolog\Level;
    15→use Monolog\LogRecord;
    16→use JsonSerializable;
    17→use Monolog\Test\MonologTestCase;
    18→
    19→class JsonFormatterTest extends MonologTestCase
    20→{
    21→    /**
    22→     * @covers Monolog\Formatter\JsonFormatter::__construct
    23→     * @covers Monolog\Formatter\JsonFormatter::getBatchMode
    24→     * @covers Monolog\Formatter\JsonFormatter::isAppendingNewlines
    25→     */
    26→    public function testConstruct()
    27→    {
    28→        $formatter = new JsonFormatter();
    29→        $this->assertEquals(JsonFormatter::BATCH_MODE_JSON, $formatter->getBatchMode());
    30→        $this->assertEquals(true, $formatter->isAppendingNewlines());
    31→        $formatter = new JsonFormatter(JsonFormatter::BATCH_MODE_NEWLINES, false);
    32→        $this->assertEquals(JsonFormatter::BATCH_MODE_NEWLINES, $formatter->getBatchMode());
    33→        $this->assertEquals(false, $formatter->isAppendingNewlines());
    34→    }
    35→
    36→    /**
    37→     * @covers Monolog\Formatter\JsonFormatter::format
    38→     */
    39→    public function testFormat()
    40→    {
    41→        $formatter = new JsonFormatter();
    42→        $record = $this->getRecord();
    43→        $this->assertEquals(json_encode($record->toArray(), JSON_FORCE_OBJECT)."\n", $formatter->format($record));
    44→
    45→        $formatter = new JsonFormatter(JsonFormatter::BATCH_MODE_JSON, false);
    46→        $record = $this->getRecord();
    47→        $this->assertEquals('{"message":"test","context":{},"level":300,"level_name":"WARNING","channel":"test","datetime":"'.$record->datetime->format('Y-m-d\TH:i:s.uP').'","extra":{}}', $formatter->format($record));
    48→    }
    49→
    50→    /**
    51→     * @covers Monolog\Formatter\JsonFormatter::format
    52→     */
    53→    public function testFormatWithPrettyPrint()
    54→    {
    55→        $formatter = new JsonFormatter();
    56→        $formatter->setJsonPrettyPrint(true);
    57→        $record = $this->getRecord();
    58→        $this->assertEquals(json_encode($record->toArray(), JSON_PRETTY_PRINT | JSON_FORCE_OBJECT)."\n", $formatter->format($record));
    59→
    60→        $formatter = new JsonFormatter(JsonFormatter::BATCH_MODE_JSON, false);
    61→        $formatter->setJsonPrettyPrint(true);
    62→        $record = $this->getRecord();
    63→        $this->assertEquals(
    64→            '{
    65→    "message": "test",
    66→    "context": {},
    67→    "level": 300,
    68→    "level_name": "WARNING",
    69→    "channel": "test",
    70→    "datetime": "'.$record->datetime->format('Y-m-d\TH:i:s.uP').'",
    71→    "extra": {}
